def q(id, difficulty, question, choices, answer, explanation, tags):
    """Build a single question dict (without category — added during duplication)."""
    return {
        "difficulty": difficulty,
        "question": question,
        "choices": choices,
        "answer": answer,
        "explanation": explanation,
        "tags": tags,
    }

